#include <iostream>
#include <string>
using namespace std;

string findLongestCommonSubstring(const string &s1, const string &s2) {
    int maxLen = 0;
    int startPos = 0;
    int len1 = s1.length();
    int len2 = s2.length();

    for (int i = 0; i < len1; ++i) {
        for (int j = 0; j < len2; ++j) {
            int k = 0;
            while (i + k < len1 && j + k < len2 && s1[i + k] == s2[j + k]) {
                ++k;
            }
            if (k > maxLen) {
                maxLen = k;
                startPos = i;
            }
        }
    }

    return s1.substr(startPos, maxLen);
}

int main() {
    string s1, s2;
    getline(cin, s1);
    getline(cin, s2);

    string result = findLongestCommonSubstring(s1, s2);
    cout << result << endl;

    return 0;
}
